  ('retired-7c9828ae-moex-00126', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3d2b73b6', 'sub-retired-7c9828ae-02', NULL, 'single_choice', '依司法院釋字第745號解釋意旨，所得稅法關於薪資所得計算，僅許薪資所得者就個人薪資收入，減除定 額之薪資所得特別扣除額，而不許薪資所得者於該年度之必要費用超過法定扣除額時，得以列舉或其他方 式減除必要費用，於此範圍內，係違反下列何者？', '["依法行政原則", "法律保留原則", "租稅法律原則", "平等原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL)
